const items = $input.all();
function extractContent(m) {
  if (m == null) return '';
  if (typeof m === 'string') return m;
  if (typeof m.content === 'string') return m.content;
  if (m.data) {
    if (typeof m.data.content === 'string') return m.data.content;
    if (Array.isArray(m.data.content)) return m.data.content.map(c => (typeof c === 'string' ? c : (c && c.text) || '')).join(' ');
  }
  if (m.kwargs && typeof m.kwargs.content === 'string') return m.kwargs.content;
  if (typeof m.message === 'string') return m.message;
  if (typeof m.text === 'string') return m.text;
  return '';
}
function extractRole(m) {
  const t = (m && m.type) || '';
  if (/human/i.test(t)) return 'Cliente';
  if (/ai|assistant|bot/i.test(t)) return 'Tomas (bot)';
  if (m && m.id && Array.isArray(m.id)) {
    const last = m.id[m.id.length-1];
    if (/Human/i.test(last)) return 'Cliente';
    if (/AI|Assistant/i.test(last)) return 'Tomas (bot)';
  }
  return 'Desconocido';
}
return items.map((item, idx) => {
  const hist = item.json;
  const src = ($('Buscar Pendientes').all()[idx] || {}).json || {};
  const history = Array.isArray(hist.chat_history) ? hist.chat_history.slice().reverse() : [];
  const conversation = history.map(m => extractRole(m) + ': ' + extractContent(m)).join('\n');
  return {
    json: {
      phone: src.phone,
      phone_from: src.phone_from,
      customer_name: src.customer_name,
      last_bot_message_at: src.last_bot_message_at,
      conversation,
      has_history: history.length > 0,
      _raw_sample: history[0] || null
    }
  };
});

const items = $input.all();
return items.map((item, idx) => {
  const raw = item.json.text || item.json.output || item.json.response || '';
  let parsed = null;
  try {
    const clean = String(raw).replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    parsed = JSON.parse(clean);
  } catch (e) {
    const m = String(raw).match(/\{[\s\S]*\}/);
    if (m) {
      try { parsed = JSON.parse(m[0]); } catch (e2) {}
    }
  }
  if (!parsed || typeof parsed !== 'object') {
    parsed = { should_followup: true, reason: 'parse_error' };
  }
  const ctx = $('Formatear Contexto').all()[idx] ? $('Formatear Contexto').all()[idx].json : {};
  return {
    json: {
      phone: ctx.phone,
      phone_from: ctx.phone_from,
      customer_name: ctx.customer_name,
      should_followup: !!parsed.should_followup,
      reason: String(parsed.reason || '').slice(0, 100)
    }
  };
});

const item = $input.first().json;
return {
  json: {
    phone: item.phone,
    from: item.phone_from,
    to: item.phone,
    type: 'audio',
    audio: {
      link: 'https://nrbakrbxbvbnexnjmjzz.supabase.co/storage/v1/object/public/audio/WhatsApp%20Ptt%202026-03-05%20at%202.55.47%20PM.ogg'
    }
  }
};

parameters.query:
SELECT COALESCE(
  (SELECT json_agg(sub.message ORDER BY sub.id DESC)
   FROM (
     SELECT id, message FROM chat_histories
     WHERE session_id = $1
     ORDER BY id DESC
     LIMIT 8
   ) sub),
  '[]'::json
) AS chat_history;

